Here are the unit tests for the `flatten_dict` function using `pytest`.

The tests are organized into three categories:
1.  **Happy Path**: Standard usage scenarios (empty, flat, nested, deep).
2.  **Edge Cases**: Boundary conditions (custom separators, falsy values, empty nested dicts, non-string keys).
3.  **Error Cases**: Invalid inputs (non-dict types).

```python
import pytest

# The function to be tested
def flatten_dict(d: dict, parent_key: str = '', sep: str = '.') -> dict:
    items = []
    for k, v in d.items():
        new_key = f'{parent_key}{sep}{k}' if parent_key else k
        if isinstance(v, dict):
            items.extend(flatten_dict(v, new_key, sep).items())
        else:
            items.append((new_key, v))
    return dict(items)

# ==========================================
# 1. Happy Path Tests
# ==========================================

def test_flatten_empty_dict():
    """Test case: Input is an empty dictionary."""
    assert flatten_dict({}) == {}

def test_flatten_flat_dict():
    """Test case: Input is a dictionary with no nesting."""
    assert flatten_dict({'a': 1, 'b': 2}) == {'a': 1, 'b': 2}

def test_flatten_nested_dict():
    """Test case: Input has a single level of nesting."""
    assert flatten_dict({'a': {'b': 2}}) == {'a.b': 2}

def test_flatten_deep_nesting():
    """Test case: Input has multiple levels of nesting."""
    d = {'a': {'b': {'c': {'d': 4}}}}
    assert flatten_dict(d) == {'a.b.c.d': 4}

# ==========================================
# 2. Edge Case Tests
# ==========================================

def test_flatten_custom_separator():
    """Test case: Using a custom separator character."""
    assert flatten_dict({'a': {'b': 1}}, sep='/') == {'a/b': 1}

def test_flatten_falsy_values():
    """Test case: Dictionary containing falsy values (0, None, False, empty string)."""
    d = {'a': 0, 'b': None, 'c': False, 'd': ''}
    # Ensure falsy values are preserved and not treated as missing
    assert flatten_dict(d) == {'a': 0, 'b': None, 'c': False, 'd': ''}

def test_flatten_empty_nested_dict():
    """Test case: Dictionary containing an empty nested dictionary.

    Note: The current implementation drops keys that point to empty dicts
    because there are no leaf items to flatten.
    """
    assert flatten_dict({'a': {}}) == {}

def test_flatten_integer_keys():
    """Test case: Dictionary keys are integers (converted to strings by f-string)."""
    assert flatten_dict({1: 'val', 2: 'val2'}) == {'1': 'val', '2': 'val2'}

def test_flatten_list_values():
    """Test case: Values are lists (not flattened, as they are not dicts)."""
    assert flatten_dict({'a': [1, 2], 'b': {'c': 3}}) == {'a': [1, 2], 'b.c': 3}

def test_flatten_with_parent_key():
    """Test case: Using the optional parent_key argument."""
    assert flatten_dict({'a': 1}, parent_key='root') == {'root.a': 1}

# ==========================================
# 3. Error Case Tests
# ==========================================

def test_flatten_invalid_input_list():
    """Test case: Input is a list (not a dictionary)."""
    with pytest.raises(AttributeError):
        flatten_dict([1, 2, 3])

def test_flatten_invalid_input_none():
    """Test case: Input is None."""
    with pytest.raises(AttributeError):
        flatten_dict(None)

def test_flatten_invalid_input_string():
    """Test case: Input is a string (not a dictionary)."""
    with pytest.raises(AttributeError):
        flatten_dict("not a dict")
```

### Explanation of Test Coverage

*   **`test_flatten_empty_dict`**: Verifies the base case where the loop doesn't execute.
*   **`test_flatten_flat_dict`**: Verifies that non-dict values are appended directly without key modification.
